async def _async_check_docker() -> CheckResult:
    """异步检测 Docker 是否安装且 daemon 可用。"""
    try:
        proc = await asyncio.create_subprocess_exec(
            "docker",
            "info",
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.PIPE,
        )
        _, stderr = await asyncio.wait_for(proc.communicate(), timeout=10)
        if proc.returncode == 0:
            return CheckResult(
                id="docker_installed",
                label="Docker 引擎",
                status="ok",
                message="Docker daemon 运行中",
            )
        err_text = stderr.decode("utf-8", errors="replace").strip()
        return CheckResult(
            id="docker_installed",
            label="Docker 引擎",
            status="fail",
            message=f"Docker daemon 不可用: {err_text[:200]}",
            fix_hint="请安装并启动 Docker Desktop: https://docs.docker.com/get-docker/",
        )
    except FileNotFoundError:
        return CheckResult(
            id="docker_installed",
            label="Docker 引擎",
            status="fail",
            message="系统未安装 Docker",
            fix_hint="请安装 Docker Desktop: https://docs.docker.com/get-docker/",
        )
    except asyncio.TimeoutError:
        return CheckResult(
            id="docker_installed",
            label="Docker 引擎",
            status="fail",
            message="Docker 响应超时（10 秒）",
            fix_hint="请检查 Docker Desktop 是否正在启动中，稍后重试",
        )


async def _async_check_docker_version() -> CheckResult:
    """异步检测 Docker 版本 ≥ 20.10。"""
    try:
        proc = await asyncio.create_subprocess_exec(
            "docker",
            "version",
            "--format",
            "{{.Server.Version}}",
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.PIPE,
        )
        stdout, _ = await asyncio.wait_for(proc.communicate(), timeout=10)
        if proc.returncode != 0:
            return CheckResult(
                id="docker_version",
                label="Docker 版本",
                status="fail",
                message="无法获取 Docker 版本",
                fix_hint="请确认 Docker daemon 已启动",
            )
        ver_str = stdout.decode("utf-8", errors="replace").strip()
        parts = ver_str.split(".")
        if len(parts) >= 2:
            major, minor = int(parts[0]), int(parts[1])
            if (major, minor) >= (20, 10):
                return CheckResult(
                    id="docker_version",
                    label="Docker 版本",
                    status="ok",
                    message=f"Docker {ver_str} ≥ 20.10",
                )
            return CheckResult(
                id="docker_version",
                label="Docker 版本",
                status="fail",
                message=f"Docker {ver_str} 过低，需要 ≥ 20.10",
                fix_hint="请升级 Docker Desktop 到最新版本",
            )
        return CheckResult(
            id="docker_version",
            label="Docker 版本",
            status="warn",
            message=f"无法解析版本号: {ver_str}",
        )
    except (FileNotFoundError, asyncio.TimeoutError):
        return CheckResult(
            id="docker_version",
            label="Docker 版本",
            status="fail",
            message="Docker 不可用",
        )


