def _detect_ram() -> tuple[int, str]:
    """
    探测系统物理内存（MB），推荐部署画像。

    画像阈值（ADR 0012 §4.2）：
      gateway-kernel: default | full: optional expansion when host resources are sufficient
    """
    ram_mb = 0
    try:
        import psutil

        ram_mb = psutil.virtual_memory().total // (1024 * 1024)
    except ImportError:
        # psutil 不可用，尝试平台原生方法
        if platform.system() == "Linux":
            try:
                meminfo = Path("/proc/meminfo").read_text(encoding="utf-8")
                for line in meminfo.splitlines():
                    if line.startswith("MemTotal:"):
                        kb = int(line.split()[1])
                        ram_mb = kb // 1024
                        break
            except (OSError, ValueError):
                pass
        elif platform.system() == "Windows":
            try:
                import ctypes

                class MEMORYSTATUSEX(ctypes.Structure):
                    _fields_ = [
                        ("dwLength", ctypes.c_ulong),
                        ("dwMemoryLoad", ctypes.c_ulong),
                        ("ullTotalPhys", ctypes.c_ulonglong),
                        ("ullAvailPhys", ctypes.c_ulonglong),
                        ("ullTotalPageFile", ctypes.c_ulonglong),
                        ("ullAvailPageFile", ctypes.c_ulonglong),
                        ("ullTotalVirtual", ctypes.c_ulonglong),
                        ("ullAvailVirtual", ctypes.c_ulonglong),
                        ("ullAvailExtendedVirtual", ctypes.c_ulonglong),
                    ]

                stat = MEMORYSTATUSEX()
                stat.dwLength = ctypes.sizeof(MEMORYSTATUSEX)
                ctypes.windll.kernel32.GlobalMemoryStatusEx(ctypes.byref(stat))
                ram_mb = stat.ullTotalPhys // (1024 * 1024)
            except (OSError, AttributeError):
                pass

    # 画像推荐（P2.1: ARM 设备自动降一档）
    if ram_mb <= 0:
        return 0, "gateway-kernel"
    if ram_mb < 14336:
        return ram_mb, "gateway-kernel"
    return ram_mb, "full"


@app.get("/api/preflight")
async def preflight() -> dict[str, Any]:
    """
    Step 1: 环境预检。

    并发执行所有检查项，返回逐项结果 + 推荐画像。
    前端据此渲染 ✅/❌ 列表，全通过后亮起"下一步"。
    """
    # 所有检查异步并发执行（端口检测已包装为 async）
    docker_check, version_check, compose_check, port_check = await asyncio.gather(
        _async_check_docker(),
        _async_check_docker_version(),
        _async_check_compose(),
        _async_check_ports(),
    )

    # 纯计算型检查（ms 级，不涉及 I/O，可同步）
    disk_check = _check_disk()
    yaml_check = _check_system_yaml()
    ram_mb, profile = _detect_ram()

    checks = [docker_check, version_check, compose_check, port_check, disk_check, yaml_check]

    # P3.1: 平台检测预检项（Windows 强警告引导 WSL）
    host_os = platform.system()
    arch = platform.machine()
    is_arm = arch.lower() in ("aarch64", "armv7l", "arm64")
    if host_os == "Windows":
        checks.append(
            CheckResult(
                id="platform_detect",
                label="运行平台",
                status="warn",
                message=(
                    f"检测到 Windows ({arch}) 宿主机。"
                    "Windows Docker Desktop 文件 I/O 性能约为原生 Linux 的 1/10，"
                    "且挂载权限（chown）不生效。"
                ),
                fix_hint=(
                    "强烈建议：打开 WSL 终端，cd 到 Linux 文件系统 "
                    "(/home/user/zen70)，在 WSL 内重新执行 python start_installer.py。"
                    "这将获得 10 倍以上的 I/O 性能和完整的 Linux 权限支持。"
                ),
            )
        )
    elif is_arm:
        checks.append(
            CheckResult(
                id="platform_detect",
                label="运行平台",
                status="ok",
                message=f"ARM 架构 ({arch})，已自动调整资源画像",
            )
        )
    else:
        checks.append(
            CheckResult(
                id="platform_detect",
                label="运行平台",
                status="ok",
                message=f"{host_os} ({arch})",
            )
        )

    # RAM 检测结果也作为一项
    if ram_mb > 0:
        checks.append(
            CheckResult(
                id="ram_detect",
                label="系统内存",
                status="ok",
                message=f"检测到 {ram_mb / 1024:.1f} GB 内存，推荐画像: {profile}",
            )
        )
    else:
        checks.append(
            CheckResult(
                id="ram_detect",
                label="系统内存",
                status="warn",
                message="无法检测系统内存，使用默认画像 gateway-kernel",
            )
        )

    all_passed = all(c.status != "fail" for c in checks)

    result = PreflightResponse(
        checks=checks,
        all_passed=all_passed,
        recommended_profile=profile,
        detected_ram_mb=ram_mb,
    )
    return asdict(result)


