def _load_system_yaml() -> dict[str, Any]:
    """加载 system.yaml 为字典。失败返回空字典。"""
    if not SYSTEM_YAML.exists():
        return {}
    try:
        data = yaml.safe_load(SYSTEM_YAML.read_text(encoding="utf-8"))
        return data if isinstance(data, dict) else {}
    except (yaml.YAMLError, OSError) as e:
        logger.error("加载 system.yaml 失败: %s", e)
        return {}


def _backup_system_yaml() -> Path | None:
    """
    写入前备份 system.yaml → .backups/system.yaml.{timestamp}。

    任何 IaC 写入操作前必须调用此函数，确保可回滚。
    """
    if not SYSTEM_YAML.exists():
        return None
    try:
        BACKUP_DIR.mkdir(parents=True, exist_ok=True)
        ts = time.strftime("%Y%m%d_%H%M%S")
        backup_path = BACKUP_DIR / f"system.yaml.{ts}"
        shutil.copy2(SYSTEM_YAML, backup_path)
        logger.info("配置备份: %s", backup_path)
        return backup_path
    except OSError as e:
        logger.warning("备份 system.yaml 失败: %s", e)
        return None


def _save_system_yaml(data: dict[str, Any], *, backup: bool = True) -> bool:
    """
    保存配置到 system.yaml。

    IaC 铁律：所有变更统一写 system.yaml，由编译器渲染产物。
    优先 ruamel.yaml 保留注释，降级 PyYAML。

    Args:
        data: 要写入的配置字典。
        backup: 写入前是否创建备份（默认 True）。
    """
    if backup:
        _backup_system_yaml()

    # 确保目标目录存在（防止路径缺失导致写入失败）
    SYSTEM_YAML.parent.mkdir(parents=True, exist_ok=True)

    try:
        import io

        from ruamel.yaml import YAML as RUAMEL_YAML
        from ruamel.yaml import YAMLError as RuamelYAMLError

        ry = RUAMEL_YAML()
        ry.preserve_quotes = True
        ry.default_flow_style = False

        # 加载原文件保留注释结构，再合并新值
        if SYSTEM_YAML.exists():
            original = ry.load(SYSTEM_YAML.read_text(encoding="utf-8"))
            if original is None:
                original = {}
            _deep_update(original, data)
            target = original
        else:
            target = data

        buf = io.StringIO()
        ry.dump(target, buf)
        SYSTEM_YAML.write_text(buf.getvalue(), encoding="utf-8")
        return True
    except ImportError:
        # ruamel 不可用，降级 PyYAML（会丢失注释）
        logger.warning("ruamel.yaml 不可用，注释将丢失")
        try:
            SYSTEM_YAML.write_text(
                yaml.dump(data, allow_unicode=True, default_flow_style=False, sort_keys=False),
                encoding="utf-8",
            )
            return True
        except OSError as e:
            logger.error("PyYAML 写入失败: %s", e)
            return False
    except (OSError, RuamelYAMLError) as e:
        # 捕获 ruamel YAML 序列化错误和 I/O 异常
        logger.error("写入 system.yaml 失败: %s: %s", type(e).__name__, e)
        return False


def _deep_update(base: dict, updates: dict) -> None:
    """递归合并 updates 到 base，保留 base 的 ruamel 注释节点。"""
    for key, value in updates.items():
        if key in base and isinstance(base[key], dict) and isinstance(value, dict):
            _deep_update(base[key], value)
        else:
            base[key] = value


@app.get("/api/config/load")
async def config_load() -> dict[str, Any]:
    """
    加载当前 system.yaml 配置为 JSON。

    前端 Step 2 用此 API 填充表单、渲染服务开关。
    """
    config = _load_system_yaml()
    if not config:
        return JSONResponse(
            status_code=404,
            content={"error": "system.yaml 不存在或为空"},
        )
    return {"config": config}


@app.post("/api/config/save")
async def config_save(request: Request) -> dict[str, Any]:
    """
    保存用户配置到 system.yaml。

    IaC 铁律：所有用户输入 → system.yaml → compiler → 产物。
    安装器绝不直接操作 .env 或 docker-compose.yml。

    请求体结构:
    {
        "network": {"domain": "zen70.cn"},
        "capabilities": {"storage": {"media_path": "/mnt/media"}},
        "services": {"jellyfin": {"enabled": true}, ...},
        "deployment": {"profile": "gateway-kernel"},
        "tunnel_token": "eyJhIjoixx..."
    }
    """
    try:
        body = await request.json()
    except (json.JSONDecodeError, ValueError) as e:
        return JSONResponse(status_code=400, content={"error": f"JSON 解析失败: {e}"})

    if not isinstance(body, dict):
        return JSONResponse(status_code=400, content={"error": "请求体必须是 JSON 对象"})

    # 加载现有配置作为基础
    config = _load_system_yaml()

    # 合并用户提交的字段（只更新提交的部分，不覆盖未提交的）
    if "network" in body and isinstance(body["network"], dict):
        config.setdefault("network", {})
        _deep_update(config["network"], body["network"])

    if "capabilities" in body and isinstance(body["capabilities"], dict):
        config.setdefault("capabilities", {})
        _deep_update(config["capabilities"], body["capabilities"])

    if "deployment" in body and isinstance(body["deployment"], dict):
        config.setdefault("deployment", {})
        _deep_update(config["deployment"], body["deployment"])

    # 服务开关：只更新 enabled 字段
    if "services" in body and isinstance(body["services"], dict):
        config.setdefault("services", {})
        for svc_name, svc_data in body["services"].items():
            if isinstance(svc_data, dict) and "enabled" in svc_data:
                if svc_name in config["services"] and isinstance(config["services"][svc_name], dict):
                    config["services"][svc_name]["enabled"] = svc_data["enabled"]

    # Tunnel Token → 写入 system.yaml 的环境变量占位区
    # IaC 铁律：Token 真值由编译器 generate_secrets() 注入 .env
    tunnel_token = body.get("tunnel_token", "").strip()
    if tunnel_token:
        config.setdefault("secrets", {})
        config["secrets"]["tunnel_token"] = tunnel_token

    if _save_system_yaml(config):
        return {"status": "ok", "message": "配置已保存到 system.yaml"}
    return JSONResponse(status_code=500, content={"error": "写入 system.yaml 失败"})


@app.get("/api/config/export")
async def config_export() -> JSONResponse:
    """导出当前 system.yaml 为 JSON（供用户下载备份）。"""
    config = _load_system_yaml()
    if not config:
        return JSONResponse(status_code=404, content={"error": "system.yaml 不存在"})

    return JSONResponse(
        content=config,
        headers={"Content-Disposition": "attachment; filename=zen70-config-export.json"},
    )


@app.post("/api/config/import")
async def config_import(file: UploadFile) -> dict[str, Any]:
    """
    导入配置 JSON 文件并应用到 system.yaml。

    支持从其他部署环境导出的配置一键导入。
    """
    if not file.filename or not file.filename.endswith(".json"):
        return JSONResponse(status_code=400, content={"error": "仅支持 .json 文件"})

    # 文件大小限制：1 MB，防止超大 JSON 导致内存耗尽或 DoS。
    # UploadFile.read() 不原生限制大小，必须显式检查。
    _MAX_IMPORT_BYTES = 1 * 1024 * 1024  # 1 MB
    content = await file.read(_MAX_IMPORT_BYTES + 1)
    if len(content) > _MAX_IMPORT_BYTES:
        return JSONResponse(status_code=413, content={"error": "配置文件过大，最大允许 1 MB"})

    try:
        imported = json.loads(content.decode("utf-8"))
    except (json.JSONDecodeError, UnicodeDecodeError) as e:
        return JSONResponse(status_code=400, content={"error": f"JSON 解析失败: {e}"})

    if not isinstance(imported, dict):
        return JSONResponse(status_code=400, content={"error": "配置文件必须是 JSON 对象"})

    # 安全校验：必须有 config_version 或 version 字段
    if "config_version" not in imported and "version" not in imported:
        return JSONResponse(status_code=400, content={"error": "无效的配置文件（缺少 version 字段）"})

    # 合并导入（非覆盖），保留本地已有的不在导入文件中的字段
    existing = _load_system_yaml()
    if existing:
        _deep_update(existing, imported)
        merged = existing
    else:
        merged = imported

    if _save_system_yaml(merged):
        return {"status": "ok", "message": "配置已导入并合并保存"}
    return JSONResponse(status_code=500, content={"error": "写入 system.yaml 失败"})


# ===========================================================================
# 硬件扫描 /api/scan/hardware
# ===========================================================================


@app.get("/api/scan/hardware")
async def scan_hardware() -> dict[str, Any]:
    """
    扫描主机硬件：磁盘、GPU、内存。

    前端 Step 2 Tab 3 用此 API 展示硬件卡片。
    用户可将扫描到的磁盘绑定到 sentinel.mount_container_map。
    """
    result: dict[str, Any] = {"disks": [], "gpu": None, "ram_mb": 0}

    # RAM
    ram_mb, _ = _detect_ram()
    result["ram_mb"] = ram_mb

    # 磁盘扫描
    if platform.system() == "Linux":
        try:
            proc = await asyncio.create_subprocess_exec(
                "lsblk",
                "-J",
                "-o",
                "NAME,SIZE,TYPE,MOUNTPOINT,FSTYPE",
                stdout=asyncio.subprocess.PIPE,
                stderr=asyncio.subprocess.PIPE,
            )
            stdout, _ = await asyncio.wait_for(proc.communicate(), timeout=10)
            if proc.returncode == 0:
                data = json.loads(stdout.decode("utf-8", errors="replace"))
                for device in data.get("blockdevices", []):
                    if device.get("type") in ("disk", "part"):
                        result["disks"].append(
                            {
                                "name": device.get("name", ""),
                                "size": device.get("size", ""),
                                "type": device.get("type", ""),
                                "mountpoint": device.get("mountpoint", ""),
                                "fstype": device.get("fstype", ""),
                            }
                        )
        except (FileNotFoundError, TimeoutError, json.JSONDecodeError):
            pass
    elif platform.system() == "Windows":
        try:
            proc = await asyncio.create_subprocess_exec(
                "powershell",
                "-NoProfile",
                "-Command",
                "Get-PhysicalDisk | Select-Object FriendlyName,Size,MediaType | ConvertTo-Json",
                stdout=asyncio.subprocess.PIPE,
                stderr=asyncio.subprocess.PIPE,
            )
            stdout, _ = await asyncio.wait_for(proc.communicate(), timeout=15)
            if proc.returncode == 0:
                raw = stdout.decode("utf-8", errors="replace").strip()
                if raw:
                    disks_data = json.loads(raw)
                    if isinstance(disks_data, dict):
                        disks_data = [disks_data]
                    for disk in disks_data:
                        size_bytes = disk.get("Size", 0)
                        size_gb = f"{size_bytes / (1024 ** 3):.0f} GB" if size_bytes else "未知"
                        result["disks"].append(
                            {
                                "name": disk.get("FriendlyName", "未知磁盘"),
                                "size": size_gb,
                                "type": disk.get("MediaType", ""),
                                "mountpoint": "",
                                "fstype": "",
                            }
                        )
        except (FileNotFoundError, TimeoutError, json.JSONDecodeError):
            pass

    # GPU 扫描
    try:
        proc = await asyncio.create_subprocess_exec(
            "nvidia-smi",
            "--query-gpu=name,memory.total",
            "--format=csv,noheader,nounits",
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.PIPE,
        )
        stdout, _ = await asyncio.wait_for(proc.communicate(), timeout=10)
        if proc.returncode == 0:
            gpu_line = stdout.decode("utf-8", errors="replace").strip()
            if gpu_line:
                parts = [p.strip() for p in gpu_line.split(",")]
                result["gpu"] = {
                    "name": parts[0] if parts else "未知 GPU",
                    "vram_mb": int(parts[1]) if len(parts) > 1 and parts[1].isdigit() else 0,
                }
    except (FileNotFoundError, asyncio.TimeoutError):
        pass

    return result


# ===========================================================================
# /api/status — 增强版：返回容器状态 + 部署模式检测
# ===========================================================================


@app.get("/api/status")
async def get_status() -> dict[str, Any]:
    """
    检测当前部署状态。

    前端据此判断显示模式：
    - deployed=false → 首次安装（完整三步向导）
    - deployed=true  → 变更模式（跳过 Step 1，直接进 Step 2）
    """
    result: dict[str, Any] = {
        "deployed": False,
        "docker_available": False,
        "compose_exists": DOCKER_COMPOSE_FILE.exists(),
        "env_exists": ENV_FILE.exists(),
        "system_yaml_exists": SYSTEM_YAML.exists(),
        "containers_running": 0,
        "containers_total": 0,
        "services": [],
    }

    try:
        proc = await asyncio.create_subprocess_exec(
            "docker",
            "ps",
            "-a",
            "--filter",
            f"label=com.docker.compose.project={COMPOSE_PROJECT_NAME}",
            "--format",
            "{{.Names}}\t{{.Status}}",
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.PIPE,
        )
        stdout, _ = await asyncio.wait_for(proc.communicate(), timeout=10)
        result["docker_available"] = True

        if proc.returncode == 0 and stdout:
            decoded = stdout.decode("utf-8", errors="replace").strip()
            if decoded:
                lines = [line.strip() for line in decoded.splitlines() if line.strip()]
                result["containers_total"] = len(lines)
                for line in lines:
                    parts = line.split("\t", 1)
                    name = parts[0] if parts else ""
                    status = parts[1] if len(parts) > 1 else ""
                    is_up = "up" in status.lower()
                    if is_up:
                        result["containers_running"] += 1
                    result["services"].append(
                        {
                            "name": name,
                            "status": status,
                            "running": is_up,
                        }
                    )
                # 有运行中的容器 = 已部署
                if result["containers_running"] > 0:
                    result["deployed"] = True
    except (asyncio.TimeoutError, FileNotFoundError, OSError) as exc:
        logger.warning("Docker 探测失败: %s: %s", type(exc).__name__, exc)

    return result


# ===========================================================================
# Step 3: 部署 /api/deploy (SSE)
# ===========================================================================


@app.get("/api/deploy")
async def deploy() -> StreamingResponse:
    """
    SSE 流式部署管道。

    流程：
      [PHASE:0] 配置编译（compiler.py —— IaC 唯一管道）
      [PHASE:1] 基础设施部署（bootstrap.py + docker compose up）
      [PHASE:2] 健康检查（gateway /health 探针）
      [PHASE:DONE] 完成

    IaC 合规：不直接操作 .env 或 docker-compose.yml，
             全部由 compiler → bootstrap 管道完成。

    并发安全：全局互斥锁保证同时只有一个部署进程。
    """

    async def _sse_generator():
        global _deploy_active  # noqa: PLW0603

        # 互斥锁：严禁并发部署（前端双击防抖 + 后端双保险）
        if _deploy_active:
            yield "data: [错误] 已有部署任务正在执行，请等待完成\n\n"
            yield "data: [EOF] Process completed with exit code 1\n\n"
            return

        async with _get_deploy_lock():
            _deploy_active = True
            try:
                async for chunk in _deploy_pipeline():
                    yield chunk
            finally:
                _deploy_active = False

    return StreamingResponse(
        _sse_generator(),
        media_type="text/event-stream",
        headers=_SSE_HEADERS,
    )


async def _deploy_pipeline():
    """部署管道核心逻辑（由 deploy() 的互斥锁保护）。"""
    env = os.environ.copy()
    env["PYTHONIOENCODING"] = "utf-8"

    # ━━━━━━━━━━ PHASE 0: 配置编译 ━━━━━━━━━━
    yield "data: [PHASE:0] ⚙️ 配置编译阶段\n\n"

    if not SYSTEM_YAML.exists():
        yield "data: [错误] system.yaml 不存在，无法编译\n\n"
        yield "data: [EOF] Process completed with exit code 1\n\n"
        return

    # 调用 compiler.py（含自动迁移 + lint + policy + 渲染）
    # 必须传入 system.yaml 路径参数，否则编译器会找不到配置文件
    yield f"data: [编译器] 执行 {COMPILER_SCRIPT.name}...\n\n"
    try:
        proc = await asyncio.create_subprocess_exec(
            sys.executable,
            str(COMPILER_SCRIPT),
            str(SYSTEM_YAML),
            cwd=str(ROOT_DIR),
            env=env,
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.STDOUT,
        )
        while True:
            line = await proc.stdout.readline()
            if not line:
                break
            decoded = line.decode("utf-8", errors="replace").strip()
            if decoded:
                yield f"data: [编译器] {decoded}\n\n"

        await proc.wait()
        if proc.returncode != 0:
            yield f"data: [错误] 编译器退出码 {proc.returncode}\n\n"
            yield f"data: [EOF] Process completed with exit code {proc.returncode}\n\n"
            return
        yield "data: [编译器] ✅ 编译完成\n\n"
    except OSError as e:
        yield f"data: [错误] 编译器启动失败: {e}\n\n"
        yield "data: [EOF] Process completed with exit code 1\n\n"
        return

    # ━━━━━━━━━━ PHASE 1: 基础设施部署 ━━━━━━━━━━
    yield "data: [PHASE:1] 🚀 基础设施部署阶段\n\n"

    # 从 system.yaml 读取用户选择的部署平台
    deploy_platform = "auto"
    try:
        import yaml as _yaml
        with open(str(SYSTEM_YAML), encoding="utf-8") as _f:
            _sys_cfg = _yaml.safe_load(_f) or {}
        deploy_platform = (_sys_cfg.get("deployment") or {}).get("platform", "auto")
    except (OSError, ValueError, KeyError) as _e:
        yield f"data: [点火引擎] ⚠️ 读取平台配置失败({_e})，使用自动检测\n\n"

    # P1.5: 跳过预检/拉取（已由 installer Step 1-2 完成）
    boot_cmd = [
        sys.executable, str(BOOTSTRAP_SCRIPT),
        "--skip-pull", "--skip-mounts",
        "--platform", deploy_platform,
    ]
    yield f"data: [点火引擎] 启动 {BOOTSTRAP_SCRIPT.name} (平台: {deploy_platform})...\n\n"

    # 法典 §1.3: 点火失败自动重试 1 次
    max_attempts = 2
    boot_success = False
    boot_rc = 1

    for attempt in range(1, max_attempts + 1):
        if attempt > 1:
            yield f"data: [点火引擎] 🔄 重试 ({attempt}/{max_attempts})...\n\n"
            await asyncio.sleep(3)

        try:
            proc = await asyncio.create_subprocess_exec(
                *boot_cmd,
                cwd=str(ROOT_DIR),
                env=env,
                stdout=asyncio.subprocess.PIPE,
                stderr=asyncio.subprocess.STDOUT,
            )
            while True:
                line = await proc.stdout.readline()
                if not line:
                    break
                decoded = line.decode("utf-8", errors="replace").strip()
                if decoded:
                    yield f"data: {decoded}\n\n"

            await proc.wait()
            boot_rc = proc.returncode or 1

            if proc.returncode == 0:
                boot_success = True
                boot_rc = 0
                break
            yield f"data: [点火引擎] ⚠️ 退出码 {proc.returncode}\n\n"
        except OSError as e:
            yield f"data: [点火引擎] ❌ 启动失败: {e}\n\n"

    if not boot_success:
        yield f"data: [点火引擎] ❌ 经 {max_attempts} 次尝试仍失败\n\n"
        yield f"data: [EOF] Process completed with exit code {boot_rc}\n\n"
        return

    yield "data: [点火引擎] ✅ 执行完毕\n\n"

    # ━━━━━━━━━━ PHASE 2: 健康检查 ━━━━━━━━━━
    yield "data: [PHASE:2] 🏥 服务健康检查\n\n"

    # P1.3: 改用 docker inspect 获取容器健康状态，绕开 Windows NAT/WSL 网络玄学
    # 法典 §1.2: 容器名从 system.yaml IaC 事实来源读取
    gateway_container = "zen70-gateway"  # 兜底默认
    try:
        sys_cfg = _load_system_yaml()
        gateway_container = (sys_cfg.get("services") or {}).get("gateway", {}).get("container_name", "zen70-gateway")
    except Exception:
        pass
    health_ok = False
    max_health = 15
    for i in range(1, max_health + 1):
        await asyncio.sleep(3)
        try:
            probe = await asyncio.create_subprocess_exec(
                "docker", "inspect",
                "--format", "{{.State.Health.Status}}",
                gateway_container,
                stdout=asyncio.subprocess.PIPE,
                stderr=asyncio.subprocess.PIPE,
            )
            out, _ = await asyncio.wait_for(probe.communicate(), timeout=10)
            if probe.returncode == 0:
                status_text = out.decode("utf-8", errors="replace").strip()
                if status_text == "healthy":
                    yield f"data: [健康检查] ✅ 网关容器就绪 (status={status_text})\n\n"
                    health_ok = True
                    break
                yield f"data: [健康检查] 🔄 第 {i}/{max_health} 次检查 (status={status_text})…\n\n"
            else:
                yield f"data: [健康检查] 🔄 第 {i}/{max_health} 次检查（容器未就绪）…\n\n"
        except asyncio.TimeoutError:
            yield f"data: [健康检查] 🔄 第 {i}/{max_health} 次超时…\n\n"
        except OSError:
            yield f"data: [健康检查] 🔄 第 {i}/{max_health} 次连接失败…\n\n"

    if not health_ok:
        yield "data: [健康检查] ⚠️ 未通过，服务可能仍在启动中\n\n"

    # ━━━━━━━━━━ PHASE DONE ━━━━━━━━━━
    yield "data: [PHASE:DONE] ✅ 部署完成\n\n"
    yield f"data: [EOF] Process completed with exit code {boot_rc}\n\n"


